import { z } from 'zod'

/**
 * Latitude constrained to -90 to 90 degrees
 */
export const LatitudeSchema = z.number().gte(-90).lte(90)
export type Latitude = z.infer<typeof LatitudeSchema>

/**
 * Longitude constrained to -180 to 180 degrees
 */
export const LongitudeSchema = z.number().gte(-180).lte(180)
export type Longitude = z.infer<typeof LongitudeSchema>

/**
 * Hour constrained to 0-23
 */
export const HourSchema = z.number().int().gte(0).lte(23)
export type Hour = z.infer<typeof HourSchema>

/**
 * Month constrained to 1-12
 */
export const MonthSchema = z.number().int().gte(1).lte(12)
export type Month = z.infer<typeof MonthSchema>

/**
 * Day constrained to 1-31
 */
export const DaySchema = z.number().int().gte(1).lte(31)
export type Day = z.infer<typeof DaySchema>

/**
 * Array of 2 hours [start, end]
 */
export const HourRangeSchema = z.array(HourSchema).length(2)
export type HourRange = z.infer<typeof HourRangeSchema>

/**
 * Array of 1-2 months [start] or [start, end]
 */
export const MonthRangeSchema = z.array(MonthSchema).min(1).max(2)
export type MonthRange = z.infer<typeof MonthRangeSchema>

/**
 * Array of 2 days [start, end]
 */
export const DayRangeSchema = z.array(DaySchema).length(2)
export type DayRange = z.infer<typeof DayRangeSchema>

/**
 * Array of floats with minimum length of 1
 */
export const DataListSchema = z.array(z.number()).min(1)
export type DataList = z.infer<typeof DataListSchema>

/**
 * Time filter stamp
 */
export const TimeFilterStampSchema = z.object({
  month: MonthSchema,
  day: DaySchema,
  hour: HourSchema,
})

export type TimeFilterStamp = z.infer<typeof TimeFilterStampSchema>

/**
 * Time filter period (start and end)
 */
export const TimeFilterPeriodSchema = z.object({
  start: TimeFilterStampSchema,
  end: TimeFilterStampSchema,
})

export type TimeFilterPeriod = z.infer<typeof TimeFilterPeriodSchema>

/**
 * Time filter (optional day/hour ranges as strings)
 */
export const TimeFilterSchema = z.object({
  day: z.string().optional(),
  hour: z.string().optional(),
})

export type TimeFilter = z.infer<typeof TimeFilterSchema>

/**
 * Date filters (period + optional filter)
 */
export const DateFiltersSchema = z.object({
  period: TimeFilterPeriodSchema,
  filter: TimeFilterSchema.optional(),
})

export type DateFilters = z.infer<typeof DateFiltersSchema>

/**
 * Timeframe filters for weather data API (legacy, kept for backward compatibility)
 */
export const TimeFiltersSchema = z.object({
  period: TimeFilterPeriodSchema,
  filter: TimeFilterSchema.optional(),
})

export type TimeFilters = z.infer<typeof TimeFiltersSchema>

/**
 * Schema for nested dateFilters structure used in analysis inputs
 */
export const DateFiltersWrapperSchema = z.object({
  dateFilters: DateFiltersSchema,
})

export type DateFiltersWrapper = z.infer<typeof DateFiltersWrapperSchema>

/** Maximum day-of-month per calendar month (Feb=29, leap-tolerant — TimePeriod
 *  carries no year, so accepting Feb 29 mirrors Python's behaviour). */
const MAX_DAY_PER_MONTH: Record<number, number> = {
  1: 31,
  2: 29,
  3: 31,
  4: 30,
  5: 31,
  6: 30,
  7: 31,
  8: 31,
  9: 30,
  10: 31,
  11: 30,
  12: 31,
}

/**
 * Time period for analysis requests, matching Python SDK's `TimePeriod`.
 * Serialized to kebab-case via `serializeToKebab` at the HTTP layer
 * (`time-period: { start-month, start-day, start-hour, end-month, end-day, end-hour }`).
 *
 * Cross-field validation matches Python's `_validate_calendar_window`:
 * rejects out-of-range days (e.g. April 31), rejects zero-length and
 * end-before-start windows.
 */
export const TimePeriodSchema = z
  .object({
    startMonth: MonthSchema,
    startDay: DaySchema,
    startHour: HourSchema,
    endMonth: MonthSchema,
    endDay: DaySchema,
    endHour: HourSchema,
  })
  .superRefine((tp, ctx) => {
    if (tp.startDay > MAX_DAY_PER_MONTH[tp.startMonth]) {
      ctx.addIssue({
        code: 'custom',
        message: `startDay=${tp.startDay} is invalid for startMonth=${tp.startMonth}`,
        path: ['startDay'],
      })
    }
    if (tp.endDay > MAX_DAY_PER_MONTH[tp.endMonth]) {
      ctx.addIssue({
        code: 'custom',
        message: `endDay=${tp.endDay} is invalid for endMonth=${tp.endMonth}`,
        path: ['endDay'],
      })
    }
    const start: [number, number, number] = [tp.startMonth, tp.startDay, tp.startHour]
    const end: [number, number, number] = [tp.endMonth, tp.endDay, tp.endHour]
    const cmp = (a: typeof start, b: typeof end): number =>
      a[0] !== b[0] ? a[0] - b[0] : a[1] !== b[1] ? a[1] - b[1] : a[2] - b[2]
    const c = cmp(start, end)
    if (c > 0) {
      ctx.addIssue({
        code: 'custom',
        message: `TimePeriod end (${end.join('/')}) is before start (${start.join('/')})`,
        path: ['endMonth'],
      })
    } else if (c === 0) {
      ctx.addIssue({
        code: 'custom',
        message: `TimePeriod is zero-length (start == end)`,
        path: ['endHour'],
      })
    }
  })

export type TimePeriod = z.infer<typeof TimePeriodSchema>

/**
 * Dotbim schema
 */
export const DotBimMeshSchema = z.object({
  mesh_id: z.number(),
  coordinates: z.array(z.number()),
  indices: z.array(z.number()).optional(),
})
export type DotBimMesh = z.infer<typeof DotBimMeshSchema>
