import { z } from 'zod'
import {
  DataListSchema,
  DateFiltersSchema,
  DotBimMeshSchema,
  LatitudeSchema,
  LongitudeSchema,
  TimePeriodSchema,
} from '../types'

import {
  AnalysesName,
  PwcCriteria,
  type PwcCriteria as PwcCriteriaType,
  ThermalComfortStatisticsSubType,
} from './constants'
import { WeatherDataPointSchema } from './weather-data'

/**
 * Full EPW weather data structure with arrays of 8760 hourly values
 * This represents the complete weather file data before filtering
 */
export const EPWDataSchema = z.object({
  year: z.array(z.number()),
  month: z.array(z.number()),
  day: z.array(z.number()),
  hour: z.array(z.number()),
  minute: z.array(z.number()),
  dryBulbTemperature: z.array(z.number()),
  dewPointTemperature: z.array(z.number()),
  relativeHumidity: z.array(z.number()),
  atmosphericStationPressure: z.array(z.number()),
  extraterrestrialHorizontalRadiation: z.array(z.number()),
  extraterrestrialDirectNormalRadiation: z.array(z.number()),
  horizontalInfraredRadiationIntensity: z.array(z.number()),
  globalHorizontalRadiation: z.array(z.number()),
  directNormalRadiation: z.array(z.number()),
  diffuseHorizontalRadiation: z.array(z.number()),
  globalHorizontalIlluminance: z.array(z.number()),
  directNormalIlluminance: z.array(z.number()),
  diffuseHorizontalIlluminance: z.array(z.number()),
  zenithLuminance: z.array(z.number()),
  windDirection: z.array(z.number()),
  windSpeed: z.array(z.number()),
  totalSkyCover: z.array(z.number()),
  opaqueSkyCover: z.array(z.number()),
  visibility: z.array(z.number()),
  ceilingHeight: z.array(z.number()),
  presentWeatherObservation: z.array(z.number()),
  presentWeatherCodes: z.array(z.number()),
  precipitableWater: z.array(z.number()),
  aerosolOpticalDepth: z.array(z.number()),
  snowDepth: z.array(z.number()),
  daysSinceLastSnowfall: z.array(z.number()),
  albedo: z.array(z.number()),
  liquidPrecipitationDepth: z.array(z.number()),
  liquidPrecipitationQuantity: z.array(z.number()),
})

export type EPWData = z.infer<typeof EPWDataSchema>

/**
 * Union type for weather data - accepts either:
 * - WeatherDataPoint[] (pre-filtered array of individual data points)
 * - EPWData (full EPW data structure with arrays, to be filtered by SDK)
 */
export const WeatherDataUnionSchema = z.union([z.array(WeatherDataPointSchema), EPWDataSchema])

export type WeatherDataUnion = z.infer<typeof WeatherDataUnionSchema>

/**
 * Location schema
 */
export const LocationSchema = z.object({
  latitude: LatitudeSchema,
  longitude: LongitudeSchema,
})

export type Location = z.infer<typeof LocationSchema>

/**
 * Base analysis payload schema.
 * `groundMaterials` is an opaque `Record<string, unknown>` passthrough -- the SDK
 * does not validate, transform, or process it; it is just serialized into the API
 * request as kebab-case `ground-materials` at the wire layer.
 */
export const BaseAnalysisPayloadSchema = z.object({
  analysisType: z.enum(Object.values(AnalysesName) as [string, ...string[]]),
  geometries: z.record(z.string(), DotBimMeshSchema).optional().default({}),
  vegetation: z.record(z.string(), z.any()).optional(),
  groundMaterials: z.record(z.string(), z.unknown()).optional(),
})

export type BaseAnalysisPayload = z.infer<typeof BaseAnalysisPayloadSchema>

/**
 * Solar model request (direct-sun-hours, daylight-availability)
 */
export const SolarModelRequestSchema = BaseAnalysisPayloadSchema.extend(LocationSchema.shape)
  .extend({
    timePeriod: TimePeriodSchema,
    analysisType: z.enum([AnalysesName.DirectSunHours, AnalysesName.DaylightAvailability]),
  })

export type SolarModelRequest = z.infer<typeof SolarModelRequestSchema>

/**
 * Wind model request (wind-speed). Optional latitude/longitude — the
 * area orchestrator injects tile centroid per-tile so the server-side
 * vegetation-conversion endpoint can build its referencePoint. Mirrors
 * Python `WindModelRequest`.
 */
export const WindModelRequestSchema = BaseAnalysisPayloadSchema.extend({
  analysisType: z.literal(AnalysesName.WindSpeed),
  windSpeed: z.number().int().gt(0).lte(100),
  windDirection: z.number().int().gte(0).lte(360),
  latitude: LatitudeSchema.optional(),
  longitude: LongitudeSchema.optional(),
})

export type WindModelRequest = z.infer<typeof WindModelRequestSchema>

/**
 * SVF model request (sky-view-factors). Optional latitude/longitude —
 * the area orchestrator injects tile centroid per-tile so the server-side
 * vegetation-conversion endpoint can build its referencePoint. Without
 * it, SVF runs with vegetation injection 400 with
 * "latitude and longitude are required for vegetation conversion".
 * Mirrors Python `SvfModelRequest`.
 */
export const SvfModelRequestSchema = BaseAnalysisPayloadSchema.extend({
  analysisType: z.literal(AnalysesName.SkyViewFactors),
  latitude: LatitudeSchema.optional(),
  longitude: LongitudeSchema.optional(),
})

export type SvfModelRequest = z.infer<typeof SvfModelRequestSchema>

/**
 * Optional data list (can be empty, used for weather data fields)
 */
const OptionalDataListSchema = z.array(z.number()).default([])

/**
 * Thermal model weather data mixin
 */
export const ThermalModelWeatherDataSchema = z.object({
  horizontalInfraredRadiationIntensity: OptionalDataListSchema,
  diffuseHorizontalRadiation: OptionalDataListSchema,
  directNormalRadiation: OptionalDataListSchema,
  globalHorizontalRadiation: OptionalDataListSchema,
  dryBulbTemperature: OptionalDataListSchema,
  windSpeed: OptionalDataListSchema,
  relativeHumidity: OptionalDataListSchema,
})

export type ThermalModelWeatherData = z.infer<typeof ThermalModelWeatherDataSchema>

/**
 * TCI model base request (without weather data)
 */
export const UtciModelBaseRequestSchema = BaseAnalysisPayloadSchema.extend({
  analysisType: z.literal(AnalysesName.ThermalComfortIndex),
})

export type UtciModelBaseRequest = z.infer<typeof UtciModelBaseRequestSchema>

/**
 * TCI model request (thermal-comfort-index, aka UTCI in Python SDK)
 */
export const UtciModelRequestSchema = BaseAnalysisPayloadSchema.extend(LocationSchema.shape)
  .extend(ThermalModelWeatherDataSchema.shape)
  .extend({
    timePeriod: TimePeriodSchema,
    analysisType: z.literal(AnalysesName.ThermalComfortIndex),
  })

export type UtciModelRequest = z.infer<typeof UtciModelRequestSchema>

/**
 * TC Statistics model request (thermal-comfort-statistics)
 */
export const TCSModelRequestSchema = BaseAnalysisPayloadSchema.extend(LocationSchema.shape)
  .extend(ThermalModelWeatherDataSchema.shape)
  .extend({
    timePeriod: TimePeriodSchema,
    analysisType: z.literal(AnalysesName.ThermalComfortStatistics),
    subtype: z.enum(Object.values(ThermalComfortStatisticsSubType) as [string, ...string[]]),
  })

export type TCSModelRequest = z.infer<typeof TCSModelRequestSchema>

/**
 * Base PWC request (without weather data)
 */
export const BasePwcRequestSchema = BaseAnalysisPayloadSchema.extend({
  analysisType: z.literal(AnalysesName.PedestrianWindComfort),
  criteria: z.enum(Object.values(PwcCriteria) as [string, ...string[]]),
})

export type BasePwcRequest = z.infer<typeof BasePwcRequestSchema>

/**
 * PWC request (pedestrian-wind-comfort).
 * Wind arrays are TOP-LEVEL fields, matching Python SDK's PwcModelRequest:
 * server expects `wind-speed` and `wind-direction` at the request root,
 * NOT nested under `wind-data`.
 */
export const PwcRequestSchema = BasePwcRequestSchema.extend({
  windSpeed: DataListSchema,
  windDirection: DataListSchema,
})

export type PwcRequest = z.infer<typeof PwcRequestSchema>

export const SolarRadiationModelWeatherDataSchema = z.object({
  directNormalRadiation: OptionalDataListSchema,
  diffuseHorizontalRadiation: OptionalDataListSchema,
})
/**
 * Solar radiation model input (solar-radiation)
 */
export const SolarRadiationModelRequestSchema = BaseAnalysisPayloadSchema.extend(
  LocationSchema.shape,
)
  .extend(SolarRadiationModelWeatherDataSchema.shape)
  .extend({
    timePeriod: TimePeriodSchema,
    analysisType: z.literal(AnalysesName.SolarRadiation),
  })

export type SolarRadiationRequest = z.infer<typeof SolarRadiationModelRequestSchema>

/**
 * Union of all analysis request types
 */
export type AnalysisRequest =
  | SolarModelRequest
  | WindModelRequest
  | SvfModelRequest
  | UtciModelRequest
  | PwcRequest
  | SolarRadiationRequest
  | TCSModelRequest

// ################### Inputs from sdk ###################

/**
 * PWC input (pedestrian-wind-comfort)
 * weatherData accepts either WeatherDataPoint[] or EPWData (SDK will filter if EPWData)
 */
export const PwcInputSchema = BasePwcRequestSchema.extend({
  dateFilters: DateFiltersSchema,
  weatherData: WeatherDataUnionSchema,
})

export type PwcInput = z.infer<typeof PwcInputSchema>

/**
 * Solar model input (uses dateFilters instead of TimeStamps)
 */
export const SolarModelInputSchema = BaseAnalysisPayloadSchema.extend(LocationSchema.shape).extend({
  analysisType: z.enum([AnalysesName.DirectSunHours, AnalysesName.DaylightAvailability]),
  dateFilters: DateFiltersSchema,
})

export type SolarModelInput = z.infer<typeof SolarModelInputSchema>

/**
 * TCI model input (uses dateFilters instead of TimeStamps)
 * weatherData accepts either WeatherDataPoint[] or EPWData (SDK will filter if EPWData)
 */
export const UtciModelInputSchema = BaseAnalysisPayloadSchema.extend(LocationSchema.shape).extend({
  analysisType: z.literal(AnalysesName.ThermalComfortIndex),
  dateFilters: DateFiltersSchema,
  weatherData: WeatherDataUnionSchema,
})

export type UtciModelInput = z.infer<typeof UtciModelInputSchema>

/**
 * TCS model input (uses dateFilters instead of TimeStamps)
 * weatherData accepts either WeatherDataPoint[] or EPWData (SDK will filter if EPWData)
 */
export const TCSModelInputSchema = BaseAnalysisPayloadSchema.extend(LocationSchema.shape).extend({
  analysisType: z.literal(AnalysesName.ThermalComfortStatistics),
  dateFilters: DateFiltersSchema,
  weatherData: WeatherDataUnionSchema,
  subtype: z.enum(Object.values(ThermalComfortStatisticsSubType) as [string, ...string[]]),
})

export type TCSModelInput = z.infer<typeof TCSModelInputSchema>

/**
 * Solar radiation model input (solar-radiation)
 * weatherData accepts either WeatherDataPoint[] or EPWData (SDK will filter if EPWData)
 */
export const SolarRadiationModelInputSchema = BaseAnalysisPayloadSchema.extend(
  LocationSchema.shape,
).extend({
  analysisType: z.literal(AnalysesName.SolarRadiation),
  dateFilters: DateFiltersSchema,
  weatherData: WeatherDataUnionSchema,
})

export type SolarRadiationInput = z.infer<typeof SolarRadiationModelInputSchema>

/**
 * Union of all analysis input types (with dateFilters)
 */
export type AnalysisInput =
  | SolarModelInput
  | WindModelRequest
  | SvfModelRequest
  | UtciModelInput
  | PwcInput
  | SolarRadiationInput
  | TCSModelInput

