/**
 * Analysis Response Types
 */

/**
 * Base analysis response fields (common to all analysis types)
 */
export interface BaseAnalysisResponse {
  /** Minimum value for legend/color scale (from API) */
  minLegend?: number
  /** Maximum value for legend/color scale (from API) */
  maxLegend?: number
}

/**
 * Solar analysis response (direct-sun-hours, daylight-availability)
 */
export interface SolarAnalysisResponse extends BaseAnalysisResponse {
  analysisType: typeof AnalysesName.DirectSunHours | typeof AnalysesName.DaylightAvailability
  matrix: number[][]
  metadata?: {
    unit: string
    description: string
  }
}

/**
 * SVF analysis response (sky-view-factors)
 */
export interface SvfAnalysisResponse extends BaseAnalysisResponse {
  analysisType: typeof AnalysesName.SkyViewFactors
  matrix: number[][]
  metadata?: {
    unit: string
    description: string
  }
}

/**
 * Wind speed analysis response
 */
export interface WindSpeedResponse extends BaseAnalysisResponse {
  analysisType: typeof AnalysesName.WindSpeed
  matrix: number[][]
  metadata?: {
    unit: string
    windSpeed: number
    windDirection: number
  }
}

/**
 * Thermal comfort index response
 */
export interface UtciResponse extends BaseAnalysisResponse {
  analysisType: typeof AnalysesName.ThermalComfortIndex
  matrix: number[][]
  metadata?: {
    unit: string
    description: string
  }
}

/**
 * Pedestrian wind comfort response
 */
export interface PwcResponse extends BaseAnalysisResponse {
  analysisType: typeof AnalysesName.PedestrianWindComfort
  matrix: number[][]
  metadata?: {
    criteria: PwcCriteriaType
    unit: string
  }
}

/**
 * Union of all analysis response types
 */
export type AnalysisResponse =
  | SolarAnalysisResponse
  | SvfAnalysisResponse
  | WindSpeedResponse
  | UtciResponse
  | PwcResponse

/**
 * Type mapping from input to response
 */
export type AnalysisResponseMap = {
  [AnalysesName.DirectSunHours]: SolarAnalysisResponse
  [AnalysesName.DaylightAvailability]: SolarAnalysisResponse
  [AnalysesName.SkyViewFactors]: SvfAnalysisResponse
  [AnalysesName.WindSpeed]: WindSpeedResponse
  [AnalysesName.ThermalComfortIndex]: UtciResponse
  [AnalysesName.PedestrianWindComfort]: PwcResponse
  [AnalysesName.ThermalComfortStatistics]: UtciResponse
}

/**
 * Infer response type from input
 */
export type InferAnalysisResponse<T extends AnalysisInput> = T extends { analysisType: infer A }
  ? A extends keyof AnalysisResponseMap
    ? AnalysisResponseMap[A]
    : AnalysisResponse
  : AnalysisResponse

// ---------------------------------------------------------------------------
// Config hashing
// ---------------------------------------------------------------------------

/**
 * Banker's rounding (round-half-to-even) at 6 decimal places.
 *
 * Mirrors Python's built-in `round(v, 6)`. JS `Math.round` rounds
 * half-away-from-zero; the two diverge only at half-cell boundaries
 * (e.g. `0.0000005` → JS 1e-6, Python 0; `0.0000025` → JS 3e-6, Python 2e-6).
 * For cross-SDK schedule cache parity, configHash MUST use the same
 * rule on both sides — otherwise the same payload produces different
 * hashes from TS and Python.
 *
 * Implementation: format to 7 decimals via `toFixed(7)`, inspect the 7th
 * decimal digit, and apply banker's rule when it's a tie. Avoids the
 * `v * 1e6` multiplier which loses precision at half-bit boundaries
 * (e.g. `2.6750005 * 1e6 = 2675000.5000000005` — would falsely classify
 * as non-half under an ulp-tolerance scheme).
 */
function bankersRound6(v: number): number {
  if (!Number.isFinite(v)) return v
  if (Number.isInteger(v)) return v
  const sign = v < 0 ? '-' : ''
  const abs = Math.abs(v)
  // Format to 20 fractional digits to recover the underlying double's
  // exact decimal expansion. Avoids the `v * 1e6` precision trap.
  const fixed = abs.toFixed(20)
  const dot = fixed.indexOf('.')
  if (dot === -1) return v
  const intPart = fixed.slice(0, dot)
  const fracPart = fixed.slice(dot + 1)
  if (fracPart.length <= 6) return v
  const keep = fracPart.slice(0, 6)
  const tail = fracPart.slice(6)
  const seventh = tail[0]
  const restNonZero = /[^0]/.test(tail.slice(1))

  let roundUp: boolean
  if (seventh < '5') roundUp = false
  else if (seventh > '5' || restNonZero) roundUp = true
  else {
    // Exactly half — round to even.
    const last = Number(keep[keep.length - 1])
    roundUp = last % 2 !== 0
  }

  if (!roundUp) {
    return Number.parseFloat(`${sign}${intPart}.${keep}`)
  }

  // Compute decimal-precise +1 ulp at 6dp via BigInt on the 6-digit string.
  // Float addition `keep + 1e-6` would re-introduce the precision drift this
  // function exists to fix.
  const incremented = (BigInt(keep) + 1n).toString().padStart(6, '0')
  if (incremented.length > 6) {
    const carriedInt = (BigInt(intPart) + 1n).toString()
    return Number.parseFloat(`${sign}${carriedInt}.${incremented.slice(1)}`)
  }
  return Number.parseFloat(`${sign}${intPart}.${incremented}`)
}

/**
 * Recursively normalise a value for deterministic JSON serialisation.
 * Floats are rounded to 6 decimal places using banker's rounding to match
 * Python's `round()`. Object keys are sorted at every nesting level to
 * guarantee canonical ordering regardless of insertion order.
 */
function normaliseValue(v: unknown): unknown {
  if (typeof v === 'number') {
    // Banker's rounding — cross-SDK parity with Python's round(v, 6).
    return Number.isInteger(v) ? v : bankersRound6(v)
  }
  if (Array.isArray(v)) {
    return v.map(normaliseValue)
  }
  if (v !== null && typeof v === 'object') {
    const obj = v as Record<string, unknown>
    const result: Record<string, unknown> = {}
    for (const key of Object.keys(obj).sort()) {
      result[key] = normaliseValue(obj[key])
    }
    return result
  }
  return v
}

/**
 * Compute a deterministic SHA-256 hex digest from config fields.
 *
 * Floats are rounded to 6 decimal places before serialisation.
 * Keys are recursively sorted at every nesting level for canonical
 * ordering. Uses `crypto.subtle` for isomorphic compatibility
 * (browser + Node + CF Workers).
 *
 * @param fields - Key-value pairs representing the config-relevant fields.
 * @returns Hex-encoded SHA-256 hash string.
 *
 * @example
 * ```ts
 * const hash = await configHash({ analysis_type: 'wind-speed', wind_speed: 10 })
 * // '3a7f2c...' (64 hex chars)
 * ```
 */
export async function configHash(fields: Record<string, unknown>): Promise<string> {
  const normalised = normaliseValue(fields)
  const canonical = JSON.stringify(normalised)
  const encoded = new TextEncoder().encode(canonical)
  const hashBuffer = await crypto.subtle.digest('SHA-256', encoded)
  const hashArray = new Uint8Array(hashBuffer)
  return Array.from(hashArray)
    .map((b) => b.toString(16).padStart(2, '0'))
    .join('')
}
